{
  "name": "Podcast Evaluator: Regioni d'Italia",
  "description": "Un'applicazione avanzata per valutare automaticamente i podcast degli studenti sulle regioni italiane, basata su criteri pedagogici specifici.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface EvaluationResult {
  studentNames: string;
  groupName: string;
  region: string;
  date: string;
  scores: {
    contentAccuracy: number; // Inhalte sind richtig
    informationRichness: number; // Viele Informationen
    creativity: number; // Kreativität
    balancedParticipation: number; // Beide sprechen mit
  };
  totalPoints: number;
  comment: string;
}

export interface ProcessingStep {
  label: string;
  status: 'pending' | 'loading' | 'completed' | 'error';
}

import { GoogleGenAI, Type } from "@google/genai";
import { EvaluationResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const evaluatePodcast = async (
  audioBase64: string,
  mimeType: string,
  metadata: { studentNames: string; groupName: string; region: string }
): Promise<EvaluationResult> => {
  const model = 'gemini-3-flash-preview';

  const prompt = `
    Sei un insegnante esperto di Geografia e Comunicazione. 
    Analizza questo podcast registrato da studenti di scuola media sulla regione italiana: ${metadata.region}.

    Valuta il podcast in base ai seguenti criteri (scala 1-5):
    1. Correttezza dei contenuti (Inhalte sind richtig): I fatti storici, geografici e culturali sono corretti?
    2. Ricchezza di informazioni (Viele Informationen): Il contenuto è approfondito o superficiale?
    3. Creatività (Kreativität): Il podcast è coinvolgente, usa una struttura originale o effetti sonori?
    4. Partecipazione equilibrata (Beide sprechen mit): Se ci sono più voci, contribuiscono in modo equo? (Valuta la dinamica del dialogo).

    Restituisci i risultati in formato JSON.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType,
            data: audioBase64,
          },
        },
        { text: prompt },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          scores: {
            type: Type.OBJECT,
            properties: {
              contentAccuracy: { type: Type.NUMBER, description: "Score for content accuracy (1-5)" },
              informationRichness: { type: Type.NUMBER, description: "Score for information richness (1-5)" },
              creativity: { type: Type.NUMBER, description: "Score for creativity (1-5)" },
              balancedParticipation: { type: Type.NUMBER, description: "Score for participation (1-5)" },
            },
            required: ["contentAccuracy", "informationRichness", "creativity", "balancedParticipation"],
          },
          comment: { type: Type.STRING, description: "Professional educational feedback in Italian" },
        },
        required: ["scores", "comment"],
      },
    },
  });

  const rawJson = JSON.parse(response.text);

  const totalPoints = Object.values(rawJson.scores as Record<string, number>).reduce((a, b) => a + b, 0);

  return {
    studentNames: metadata.studentNames,
    groupName: metadata.groupName,
    region: metadata.region,
    date: new Date().toLocaleDateString('it-IT'),
    scores: rawJson.scores,
    totalPoints,
    comment: rawJson.comment,
  };
};

import React, { useState, useRef } from 'react';
import { 
  Mic, 
  Upload, 
  FileAudio, 
  CheckCircle, 
  AlertCircle, 
  Download, 
  RefreshCw,
  Map,
  Users,
  Info
} from 'lucide-react';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';
import { evaluatePodcast } from './services/geminiService';
import { EvaluationResult, ProcessingStep } from './types';

const App: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [studentNames, setStudentNames] = useState('');
  const [groupName, setGroupName] = useState('');
  const [region, setRegion] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<EvaluationResult | null>(null);
  const [steps, setSteps] = useState<ProcessingStep[]>([
    { label: 'Caricamento audio...', status: 'pending' },
    { label: 'Analisi del contenuto...', status: 'pending' },
    { label: 'Valutazione criteri...', status: 'pending' },
    { label: 'Generazione feedback...', status: 'pending' },
  ]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
    }
  };

  const updateStep = (index: number, status: ProcessingStep['status']) => {
    setSteps(prev => prev.map((step, i) => i === index ? { ...step, status } : step));
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleEvaluate = async () => {
    if (!file || !studentNames || !region) {
      setError('Inserisci tutti i campi obbligatori e carica un file audio.');
      return;
    }

    setLoading(true);
    setError(null);
    setResult(null);
    setSteps(prev => prev.map(s => ({ ...s, status: 'pending' })));

    try {
      updateStep(0, 'loading');
      const base64 = await fileToBase64(file);
      updateStep(0, 'completed');

      updateStep(1, 'loading');
      updateStep(2, 'loading');
      const evaluation = await evaluatePodcast(base64, file.type, {
        studentNames,
        groupName,
        region,
      });
      updateStep(1, 'completed');
      updateStep(2, 'completed');

      updateStep(3, 'loading');
      setResult(evaluation);
      updateStep(3, 'completed');
    } catch (err: any) {
      setError(err.message || 'Si è verificato un errore durante la valutazione.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const downloadPDF = () => {
    if (!result) return;

    const doc = new jsPDF();
    const primaryColor = [37, 99, 235]; // Tailwind blue-600

    // Header
    doc.setFontSize(22);
    doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    doc.text('Valutazione Podcast Scolastico', 14, 22);

    doc.setFontSize(12);
    doc.setTextColor(100);
    doc.text(`Regione: ${result.region}`, 14, 32);
    doc.text(`Data: ${result.date}`, 14, 38);

    // Student Info
    doc.autoTable({
      startY: 45,
      head: [['Informazioni Gruppo', 'Valore']],
      body: [
        ['Studenti', result.studentNames],
        ['Gruppo', result.groupName || 'N/A'],
      ],
      theme: 'striped',
      headStyles: { fillColor: primaryColor },
    });

    // Scores Table
    doc.autoTable({
      startY: (doc as any).lastAutoTable.finalY + 10,
      head: [['Criterio di Valutazione', 'Punteggio (1-5)']],
      body: [
        ['Correttezza dei contenuti (Inhalte sind richtig)', result.scores.contentAccuracy],
        ['Ricchezza di informazioni (Viele Informationen)', result.scores.informationRichness],
        ['Creatività (Kreativität)', result.scores.creativity],
        ['Partecipazione equilibrata (Beide sprechen mit)', result.scores.balancedParticipation],
        [{ content: 'Punteggio Totale', styles: { fontStyle: 'bold' } }, { content: `${result.totalPoints} / 20`, styles: { fontStyle: 'bold' } }],
      ],
      theme: 'grid',
      headStyles: { fillColor: primaryColor },
    });

    // Comment
    const finalY = (doc as any).lastAutoTable.finalY + 10;
    doc.setFontSize(14);
    doc.setTextColor(0);
    doc.text('Commento e Feedback:', 14, finalY);

    doc.setFontSize(11);
    doc.setTextColor(50);
    const splitComment = doc.splitTextToSize(result.comment, 180);
    doc.text(splitComment, 14, finalY + 7);

    doc.save(`Valutazione_Podcast_${result.region}_${result.studentNames.replace(/\s+/g, '_')}.pdf`);
  };

  const reset = () => {
    setFile(null);
    setResult(null);
    setError(null);
    setSteps(prev => prev.map(s => ({ ...s, status: 'pending' })));
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-4xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg">
              <Mic className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">Podcast Evaluation AI</h1>
          </div>
          <button 
            onClick={reset}
            className="text-sm font-medium text-slate-500 hover:text-blue-600 flex items-center gap-1 transition-colors"
          >
            <RefreshCw className="w-4 h-4" /> Reset
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-8">
        {!result ? (
          <div className="grid gap-8">
            {/* Input Form Section */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
              <div className="p-6 border-b border-slate-100 bg-slate-50/50">
                <h2 className="text-lg font-semibold text-slate-800 flex items-center gap-2">
                  <Info className="w-5 h-5 text-blue-500" /> Dettagli Podcast
                </h2>
              </div>
              <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-medium text-slate-700 flex items-center gap-2">
                    <Users className="w-4 h-4" /> Nomi degli Studenti *
                  </label>
                  <input 
                    type="text" 
                    value={studentNames}
                    onChange={(e) => setStudentNames(e.target.value)}
                    placeholder="Es: Maria Rossi, Luca Bianchi"
                    className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium text-slate-700 flex items-center gap-2">
                    <Map className="w-4 h-4" /> Regione Italiana *
                  </label>
                  <input 
                    type="text" 
                    value={region}
                    onChange={(e) => setRegion(e.target.value)}
                    placeholder="Es: Toscana, Sicilia..."
                    className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                  />
                </div>
                <div className="space-y-2 md:col-span-2">
                  <label className="text-sm font-medium text-slate-700 flex items-center gap-2">
                    <Info className="w-4 h-4" /> Podcast / Gruppo (opzionale)
                  </label>
                  <input 
                    type="text" 
                    value={groupName}
                    onChange={(e) => setGroupName(e.target.value)}
                    placeholder="Es: Gruppo A, I Reporter del Nord"
                    className="w-full px-4 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                  />
                </div>
              </div>
            </div>

            {/* Upload Section */}
            <div 
              className={`bg-white rounded-2xl shadow-sm border-2 border-dashed transition-all p-10 flex flex-col items-center justify-center gap-4 cursor-pointer hover:border-blue-400 group ${file ? 'border-blue-400 bg-blue-50/20' : 'border-slate-200'}`}
              onClick={() => fileInputRef.current?.click()}
            >
              <input 
                type="file" 
                ref={fileInputRef}
                onChange={handleFileChange}
                accept="audio/*"
                className="hidden"
              />
              <div className={`p-4 rounded-full transition-transform group-hover:scale-110 ${file ? 'bg-blue-100 text-blue-600' : 'bg-slate-100 text-slate-400'}`}>
                {file ? <FileAudio className="w-10 h-10" /> : <Upload className="w-10 h-10" />}
              </div>
              <div className="text-center">
                <p className="text-lg font-semibold text-slate-800">
                  {file ? file.name : 'Carica il podcast degli studenti'}
                </p>
                <p className="text-sm text-slate-500 mt-1">
                  Trascina il file audio qui o clicca per sfogliare
                </p>
              </div>
            </div>

            {/* Error Message */}
            {error && (
              <div className="bg-red-50 border border-red-200 rounded-xl p-4 flex items-start gap-3 text-red-700">
                <AlertCircle className="w-5 h-5 mt-0.5 flex-shrink-0" />
                <p className="text-sm">{error}</p>
              </div>
            )}

            {/* Action Button */}
            <button
              onClick={handleEvaluate}
              disabled={loading || !file || !studentNames || !region}
              className={`w-full py-4 rounded-2xl font-bold text-white shadow-lg shadow-blue-200 flex items-center justify-center gap-3 transition-all active:scale-[0.98] ${loading || !file || !studentNames || !region ? 'bg-slate-300 cursor-not-allowed grayscale' : 'bg-blue-600 hover:bg-blue-700'}`}
            >
              {loading ? (
                <>
                  <RefreshCw className="w-5 h-5 animate-spin" />
                  Valutazione in corso...
                </>
              ) : (
                <>
                  <CheckCircle className="w-5 h-5" />
                  Inizia Valutazione Automatica
                </>
              )}
            </button>

            {/* Loading Steps */}
            {loading && (
              <div className="bg-white rounded-2xl p-6 border border-slate-200 shadow-sm space-y-4">
                <h3 className="font-semibold text-slate-700 flex items-center gap-2">
                  Stato dell'elaborazione
                </h3>
                <div className="space-y-3">
                  {steps.map((step, idx) => (
                    <div key={idx} className="flex items-center gap-3">
                      {step.status === 'completed' ? (
                        <CheckCircle className="w-5 h-5 text-green-500" />
                      ) : step.status === 'loading' ? (
                        <RefreshCw className="w-5 h-5 text-blue-500 animate-spin" />
                      ) : (
                        <div className="w-5 h-5 rounded-full border-2 border-slate-200" />
                      )}
                      <span className={`text-sm ${step.status === 'loading' ? 'text-blue-600 font-medium' : 'text-slate-500'}`}>
                        {step.label}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : (
          /* Results View */
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden">
              <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-8 text-white">
                <div className="flex justify-between items-start">
                  <div>
                    <h2 className="text-3xl font-bold">Risultato Valutazione</h2>
                    <p className="opacity-80 mt-1 font-medium">{result.region} — {result.studentNames}</p>
                  </div>
                  <div className="bg-white/20 backdrop-blur-md rounded-2xl p-4 text-center">
                    <p className="text-4xl font-black">{result.totalPoints}</p>
                    <p className="text-xs uppercase tracking-widest font-bold opacity-80">Punti Totali</p>
                  </div>
                </div>
              </div>

              <div className="p-8">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  {/* Score Bars */}
                  <div className="space-y-6">
                    <ScoreItem 
                      label="Correttezza Contenuti" 
                      subLabel="Inhalte sind richtig"
                      score={result.scores.contentAccuracy} 
                    />
                    <ScoreItem 
                      label="Ricchezza Informazioni" 
                      subLabel="Viele Informationen"
                      score={result.scores.informationRichness} 
                    />
                    <ScoreItem 
                      label="Creatività" 
                      subLabel="Kreativität"
                      score={result.scores.creativity} 
                    />
                    <ScoreItem 
                      label="Partecipazione" 
                      subLabel="Beide sprechen mit"
                      score={result.scores.balancedParticipation} 
                    />
                  </div>

                  {/* Comment */}
                  <div className="bg-slate-50 rounded-2xl p-6 border border-slate-100">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2 mb-4">
                      Commento dell'Insegnante (AI)
                    </h3>
                    <p className="text-slate-600 leading-relaxed text-sm italic">
                      "{result.comment}"
                    </p>
                  </div>
                </div>

                <div className="mt-10 flex flex-col sm:flex-row gap-4">
                  <button
                    onClick={downloadPDF}
                    className="flex-1 bg-blue-600 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-blue-700 transition-all shadow-lg shadow-blue-100"
                  >
                    <Download className="w-5 h-5" /> Scarica Valutazione PDF
                  </button>
                  <button
                    onClick={reset}
                    className="sm:w-1/3 bg-slate-100 text-slate-600 py-4 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-slate-200 transition-all"
                  >
                    Valuta un altro podcast
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

interface ScoreItemProps {
  label: string;
  subLabel: string;
  score: number;
}

const ScoreItem: React.FC<ScoreItemProps> = ({ label, subLabel, score }) => {
  const percentage = (score / 5) * 100;

  return (
    <div className="space-y-2">
      <div className="flex justify-between items-end">
        <div>
          <p className="text-sm font-bold text-slate-800">{label}</p>
          <p className="text-[10px] text-slate-400 uppercase tracking-wider">{subLabel}</p>
        </div>
        <span className="text-sm font-bold text-blue-600">{score}/5</span>
      </div>
      <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
        <div 
          className="h-full bg-blue-500 rounded-full transition-all duration-1000"
          style={{ width: `${percentage}%` }}
        />
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { 
  Mic, 
  Upload, 
  FileAudio, 
  CheckCircle, 
  AlertCircle, 
  Download, 
  RefreshCw,
  Map,
  Users,
  Info
} from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { evaluatePodcast } from './services/geminiService';
import { EvaluationResult, ProcessingStep } from './types';

const App: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [studentNames, setStudentNames] = useState('');
  const [groupName, setGroupName] = useState('');
  const [region, setRegion] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<EvaluationResult | null>(null);
  const [steps, setSteps] = useState<ProcessingStep[]>([
    { label: 'Caricamento audio...', status: 'pending' },
    { label: 'Analisi del contenuto...', status: 'pending' },
    { label: 'Valutazione criteri...', status: 'pending' },
    { label: 'Generazione feedback...', status: 'pending' },
  ]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setError(null);
    }
  };

  const updateStep = (index: number, status: ProcessingStep['status']) => {
    setSteps(prev => prev.map((step, i) => i === index ? { ...step, status } : step));
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleEvaluate = async () => {
    if (!file || !studentNames || !region) {
      setError('Inserisci tutti i campi obbligatori (Nomi, Regione e File Audio).');
      return;
    }

    setLoading(true);
    setError(null);
    setResult(null);
    setSteps(prev => prev.map(s => ({ ...s, status: 'pending' })));

    try {
      updateStep(0, 'loading');
      const base64 = await fileToBase64(file);
      updateStep(0, 'completed');

      updateStep(1, 'loading');
      const evaluation = await evaluatePodcast(base64, file.type, {
        studentNames,
        groupName,
        region,
      });
      updateStep(1, 'completed');
      updateStep(2, 'completed');
      updateStep(3, 'completed');

      setResult(evaluation);
    } catch (err: any) {
      setError('Errore durante la valutazione: ' + (err.message || 'Errore sconosciuto'));
      setSteps(prev => prev.map(s => s.status === 'loading' ? { ...s, status: 'error' } : s));
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const downloadPDF = () => {
    if (!result) return;

    try {
      const doc = new jsPDF();
      const primaryColor: [number, number, number] = [37, 99, 235]; // Blue-600

      // Titolo e Intestazione
      doc.setFontSize(22);
      doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
      doc.text('Valutazione Podcast Scolastico', 14, 22);

      doc.setFontSize(12);
      doc.setTextColor(100);
      doc.text(`Progetto: Regioni d'Italia`, 14, 30);
      doc.text(`Regione: ${result.region}`, 14, 36);
      doc.text(`Data: ${result.date}`, 14, 42);

      // Tabella Info Studenti
      autoTable(doc, {
        startY: 50,
        head: [['Informazioni Gruppo', 'Valore']],
        body: [
          ['Studenti', result.studentNames],
          ['Gruppo/Podcast', result.groupName || 'N/A'],
        ],
        theme: 'striped',
        headStyles: { fillColor: primaryColor },
      });

      // Tabella Punteggi
      autoTable(doc, {
        startY: (doc as any).lastAutoTable.finalY + 10,
        head: [['Criterio di Valutazione', 'Punteggio (1-5)']],
        body: [
          ['Correttezza dei contenuti (Inhalte sind richtig)', result.scores.contentAccuracy],
          ['Ricchezza di informazioni (Viele Informationen)', result.scores.informationRichness],
          ['Creatività (Kreativität)', result.scores.creativity],
          ['Partecipazione equilibrata (Beide sprechen mit)', result.scores.balancedParticipation],
          [{ content: 'PUNTEGGIO TOTALE', styles: { fontStyle: 'bold', fillColor: [240, 240, 240] } }, { content: `${result.totalPoints} / 20`, styles: { fontStyle: 'bold', fillColor: [240, 240, 240] } }],
        ],
        theme: 'grid',
        headStyles: { fillColor: primaryColor },
      });

      // Commento e Feedback
      const finalY = (doc as any).lastAutoTable.finalY + 15;
      doc.setFontSize(14);
      doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
      doc.text('Feedback e Suggerimenti:', 14, finalY);

      doc.setFontSize(11);
      doc.setTextColor(40);
      const splitComment = doc.splitTextToSize(result.comment, 180);
      doc.text(splitComment, 14, finalY + 8);

      // Firma Piè di pagina
      doc.setFontSize(9);
      doc.setTextColor(150);
      doc.text('Generato automaticamente via AI Podcast Evaluator', 14, 285);

      doc.save(`Valutazione_${result.region}_${result.studentNames.replace(/\s+/g, '_')}.pdf`);
    } catch (e) {
