  Info,
  GraduationCap,
  Star
} from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { evaluatePodcast } from './services/geminiService';
import { EvaluationResult, ProcessingStep } from './types';

const App: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [studentNames, setStudentNames] = useState('');
  const [region, setRegion] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<EvaluationResult | null>(null);
  const [steps, setSteps] = useState<ProcessingStep[]>([
    { label: 'Caricamento audio...', status: 'pending' },
    { label: 'Analisi del contenuto...', status: 'pending' },
    { label: 'Valutazione criteri...', status: 'pending' },
    { label: 'Generazione feedback...', status: 'pending' },
  ]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setError(null);
    }
  };

  const updateStep = (index: number, status: ProcessingStep['status']) => {
    setSteps(prev => prev.map((step, i) => i === index ? { ...step, status } : step));
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleEvaluate = async () => {
    if (!file || !studentNames || !region) {
      setError('Inserisci tutti i campi obbligatori (Nomi, Regione e File Audio).');
      return;
    }

    setLoading(true);
    setError(null);
    setResult(null);
    setSteps(prev => prev.map(s => ({ ...s, status: 'pending' })));

    try {
      updateStep(0, 'loading');
      const base64 = await fileToBase64(file);
      updateStep(0, 'completed');

      updateStep(1, 'loading');
      updateStep(2, 'loading');
      const evaluation = await evaluatePodcast(base64, file.type, {
        studentNames,
        region,
      });
      updateStep(1, 'completed');
      updateStep(2, 'completed');
      updateStep(3, 'completed');

      setResult(evaluation);
    } catch (err: any) {
      setError('Errore durante la valutazione: ' + (err.message || 'Errore sconosciuto'));
      setSteps(prev => prev.map(s => s.status === 'loading' ? { ...s, status: 'error' } : s));
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const downloadPDF = () => {
    if (!result) return;

    try {
      const doc = new jsPDF();
      const primaryColor: [number, number, number] = [37, 99, 235]; // Blue-600

      // Header
      doc.setFontSize(22);
      doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
      doc.text('Valutazione Podcast Scolastico', 14, 22);

      doc.setFontSize(11);
      doc.setTextColor(100);
      doc.text(`Progetto: Regioni d'Italia`, 14, 30);
      doc.text(`Regione: ${result.region} | Data: ${result.date}`, 14, 36);

      // Grade Highlight in PDF Header
      doc.setFontSize(16);
      doc.setTextColor(217, 119, 6); // Amber-600
      doc.setFont('helvetica', 'bold');
      doc.text(`VOTO FINALE: ${result.finalGrade.toFixed(1)} / 6.0`, 140, 30);

      autoTable(doc, {
        startY: 45,
        head: [['Informazioni', 'Valore']],
        body: [
          ['Studenti', result.studentNames],
          ['Regione', result.region],
        ],
        theme: 'striped',
        headStyles: { fillColor: primaryColor },
      });

      autoTable(doc, {
        startY: (doc as any).lastAutoTable.finalY + 10,
        head: [['Kriterium', 'Descrizione', 'Punkte']],
        body: [
          ['Inhalte sind richtig', 'Correttezza contenuti', `${result.scores.contentAccuracy}/5`],
          ['Viele Informationen', 'Ricchezza informazioni', `${result.scores.informationRichness}/5`],
          ['Kreativität', 'Creatività e stile', `${result.scores.creativity}/5`],
          ['Beide sprechen mit', 'Partecipazione voci', `${result.scores.balancedParticipation}/5`],
          [{ content: 'GESAMTPUNKTZAHL (Totale Punti)', colSpan: 2, styles: { fontStyle: 'bold', fillColor: [240, 240, 240] } }, { content: `${result.totalPoints}/20`, styles: { fontStyle: 'bold', fillColor: [240, 240, 240] } }],
          [{ content: 'VOTO FINALE (Formato 1-6)', colSpan: 2, styles: { fontStyle: 'bold', fillColor: [254, 243, 199] } }, { content: `${result.finalGrade.toFixed(1)}/6.0`, styles: { fontStyle: 'bold', fillColor: [254, 243, 199] } }],
        ],
        theme: 'grid',
        headStyles: { fillColor: primaryColor },
      });

      const finalY = (doc as any).lastAutoTable.finalY + 15;
      doc.setFontSize(14);
      doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
      doc.text('Feedback:', 14, finalY);

      doc.setFontSize(11);
      doc.setTextColor(40);
      doc.setFont('helvetica', 'italic');
      const splitComment = doc.splitTextToSize(result.comment, 180);
      doc.text(splitComment, 14, finalY + 8);

      doc.setFontSize(8);
      doc.setTextColor(180);
      doc.text('Generato tramite AI Podcast Evaluator - Supporto alla didattica digitale', 14, 285);

      doc.save(`Valutazione_${result.region}_${result.studentNames.replace(/\s+/g, '_')}.pdf`);
    } catch (e) {
      console.error("PDF generation error:", e);
      alert("Errore nella creazione del PDF. Verifica la console.");
    }
  };

  const reset = () => {
    setFile(null);
    setResult(null);
    setError(null);
    setStudentNames('');
    setRegion('');
    setSteps(prev => prev.map(s => ({ ...s, status: 'pending' })));
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 shadow-sm">
        <div className="max-w-4xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-xl shadow-md shadow-blue-100">
              <Mic className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">Podcast Evaluator</h1>
          </div>
          <button 
            onClick={reset}
            className="text-sm font-medium text-slate-500 hover:text-blue-600 flex items-center gap-1 transition-colors px-3 py-1.5 rounded-lg hover:bg-slate-50"
          >
            <RefreshCw className="w-4 h-4" /> Reset
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-8">
        {!result ? (
          <div className="grid gap-6">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
              <div className="p-6 border-b border-slate-100 bg-slate-50/50">
                <h2 className="text-lg font-semibold text-slate-800 flex items-center gap-2">
                  <Info className="w-5 h-5 text-blue-500" /> Dettagli Valutazione
                </h2>
              </div>
              <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase">Nomi Studenti *</label>
                  <input 
                    type="text" 
                    value={studentNames}
                    onChange={(e) => setStudentNames(e.target.value)}
                    placeholder="Es: Anna e Simone"
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase">Regione *</label>
                  <input 
                    type="text" 
                    value={region}
                    onChange={(e) => setRegion(e.target.value)}
