                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  />
                </div>
              </div>
            </div>

            <div 
              className={`bg-white rounded-2xl shadow-sm border-2 border-dashed transition-all p-12 flex flex-col items-center justify-center gap-4 cursor-pointer hover:border-blue-400 group ${file ? 'border-blue-400 bg-blue-50/20' : 'border-slate-200'}`}
              onClick={() => fileInputRef.current?.click()}
            >
              <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="audio/*" className="hidden" />
              <div className={`p-5 rounded-full transition-transform group-hover:scale-110 ${file ? 'bg-blue-100 text-blue-600 shadow-lg shadow-blue-50' : 'bg-slate-100 text-slate-400'}`}>
                {file ? <FileAudio className="w-12 h-12" /> : <Upload className="w-12 h-12" />}
              </div>
              <div className="text-center">
                <p className="text-lg font-semibold text-slate-800">{file ? file.name : 'Seleziona il Podcast'}</p>
                <p className="text-sm text-slate-400 mt-1 italic">Trascina qui il file audio registrato</p>
              </div>
            </div>

            {error && (
              <div className="bg-red-50 border border-red-200 rounded-xl p-4 flex items-center gap-3 text-red-700 animate-in fade-in zoom-in duration-200">
                <AlertCircle className="w-5 h-5 flex-shrink-0" />
                <p className="text-sm font-medium">{error}</p>
              </div>
            )}

            <button
              onClick={handleEvaluate}
              disabled={loading || !file || !studentNames || !region}
              className={`w-full py-5 rounded-2xl font-bold text-white shadow-xl transition-all active:scale-[0.98] ${loading || !file || !studentNames || !region ? 'bg-slate-300 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'}`}
            >
              {loading ? <RefreshCw className="w-6 h-6 animate-spin mx-auto" /> : 'Analizza Podcast'}
            </button>

            {loading && (
              <div className="bg-white rounded-2xl p-6 border border-slate-200 shadow-sm space-y-4">
                <div className="space-y-3">
                  {steps.map((step, idx) => (
                    <div key={idx} className="flex items-center gap-3">
                      {step.status === 'completed' ? <CheckCircle className="w-5 h-5 text-green-500" /> : 
                       step.status === 'loading' ? <RefreshCw className="w-5 h-5 text-blue-500 animate-spin" /> : 
                       <div className="w-5 h-5 rounded-full border-2 border-slate-200" />}
                      <span className={`text-sm ${step.status === 'loading' ? 'text-blue-600 font-medium' : 'text-slate-500'}`}>{step.label}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700">
            <div className="bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden">
              <div className="bg-gradient-to-br from-blue-600 via-blue-700 to-indigo-800 p-10 text-white relative">
                <div className="absolute top-0 right-0 p-8 opacity-10">
                   <Mic className="w-32 h-32" />
                </div>
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 relative z-10">
                  <div className="flex-1">
                    <p className="text-xs uppercase tracking-[0.2em] opacity-80 font-black">Report Podcast</p>
                    <h2 className="text-4xl font-extrabold mt-2 tracking-tight">{result.region}</h2>
                    <p className="mt-2 font-medium bg-white/10 w-fit px-3 py-1 rounded-lg backdrop-blur-sm border border-white/10">{result.studentNames}</p>
                  </div>
                  <div className="flex flex-wrap gap-4 justify-center md:justify-end">
                    <div className="bg-white/10 backdrop-blur-md text-white rounded-3xl px-6 py-4 text-center border border-white/20">
                      <p className="text-4xl font-black leading-none">{result.totalPoints}</p>
                      <p className="text-[10px] uppercase font-bold mt-2 tracking-widest opacity-70">Punti / 20</p>
                    </div>
                    <div className="bg-amber-400 text-amber-950 rounded-3xl px-8 py-6 text-center shadow-2xl border-2 border-amber-300 transform md:scale-110">
                      <div className="flex items-center justify-center gap-2 mb-1">
                        <Star className="w-4 h-4 fill-amber-950" />
                        <span className="text-[10px] uppercase font-bold tracking-widest">Voto Finale</span>
                      </div>
                      <p className="text-6xl font-black leading-none">{result.finalGrade.toFixed(1)}</p>
                      <p className="text-xs font-bold mt-2 opacity-80 italic">Scala 1.0 - 6.0</p>
                    </div>
                  </div>
                </div>
              </div>

              <div className="p-10">
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
                  <div className="space-y-8">
                    <div className="flex items-center justify-between border-b border-slate-100 pb-2">
                      <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Analisi Criteri</h3>
                      <div className="flex items-center gap-1 text-blue-600">
                        <GraduationCap className="w-4 h-4" />
                        <span className="text-xs font-bold uppercase tracking-widest">Docente AI</span>
                      </div>
                    </div>
                    <ScoreBar label="Correttezza" sub="Inhalte sind richtig" score={result.scores.contentAccuracy} />
                    <ScoreBar label="Ricchezza Info" sub="Viele Informationen" score={result.scores.informationRichness} />
                    <ScoreBar label="Creatività" sub="Kreativität" score={result.scores.creativity} />
                    <ScoreBar label="Partecipazione" sub="Beide sprechen mit" score={result.scores.balancedParticipation} />
                  </div>

                  <div className="flex flex-col">
                    <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-100 pb-2 mb-6">Feedback</h3>
                    <div className="bg-slate-50/50 rounded-3xl p-8 border border-slate-100 relative group transition-colors hover:bg-white hover:border-blue-100 h-full flex flex-col justify-center">
                      <div className="absolute -top-3 left-8 bg-blue-600 text-white p-1 rounded-lg">
                        <CheckCircle className="w-4 h-4" />
                      </div>
                      <p className="text-slate-700 leading-relaxed text-lg font-medium italic">
                        "{result.comment}"
                      </p>
                      <div className="mt-6 pt-6 border-t border-slate-100 flex items-center gap-2 text-amber-600">
                        <Star className="w-4 h-4 fill-amber-500" />
                        <span className="text-sm font-bold">Valutazione complessiva: {result.finalGrade.toFixed(1)} / 6.0</span>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="mt-12 flex flex-col sm:flex-row gap-4">
                  <button
                    onClick={downloadPDF}
                    className="flex-1 bg-blue-600 text-white py-5 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-blue-700 transition-all shadow-xl shadow-blue-100 group"
                  >
                    <Download className="w-5 h-5 group-hover:animate-bounce" /> Scarica Report PDF (Voto: {result.finalGrade.toFixed(1)})
                  </button>
                  <button
                    onClick={reset}
                    className="sm:w-1/3 bg-slate-100 text-slate-600 py-5 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-slate-200 transition-all"
                  >
                    Nuova Analisi
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

