export interface EvaluationResult {
  studentNames: string;
  region: string;
  date: string;
  scores: {
    contentAccuracy: number; // Inhalte sind richtig
    informationRichness: number; // Viele Informationen
    creativity: number; // Kreativität
    balancedParticipation: number; // Beide sprechen mit
  };
  totalPoints: number;
  finalGrade: number; 
  comment: string;
  transcript: {
    german: string;
    italian: string;
  }[];
}

export interface ProcessingStep {
  label: string;
  status: 'pending' | 'loading' | 'completed' | 'error';
}

import { GoogleGenAI, Type } from "@google/genai";
import { EvaluationResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const evaluatePodcast = async (
  audioBase64: string,
  mimeType: string,
  metadata: { studentNames: string; region: string }
): Promise<EvaluationResult> => {
  const model = 'gemini-3-flash-preview';

  const prompt = `
    Sei un insegnante esperto di Geografia e Comunicazione. 
    Analizza questo podcast registrato da studenti di scuola media sulla regione italiana: ${metadata.region}.

    Valuta il podcast in base ai seguenti criteri (scala 1-5):
    1. Correttezza dei contenuti (Inhalte sind richtig): I fatti sono corretti?
    2. Ricchezza di informazioni (Viele Informationen): Il contenuto è approfondito?
    3. Creativitä (Kreativität): Il podcast è coinvolgente e originale?
    4. Partecipazione equilibrata (Beide sprechen mit): Le voci contribuiscono in modo equo?

    REGOLE PER IL COMMENTO:
    - Scrivi ESCLUSIVAMENTE in lingua TEDESCA (Deutsch).
    - Sii estremamente sintetico e conciso (massimo 2 frasi).
    - Evidenzia un pregio principale e un piccolo suggerimento di miglioramento.

    TRASCRIZIONE:
    - Genera una trascrizione accurata e completa di tutto il dialogo parlato nel podcast.
    - Per ogni riga di dialogo, fornisci il testo originale in TEDESCO e la traduzione professionale in ITALIANO.

    Restituisci i risultati in formato JSON.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType,
            data: audioBase64,
          },
        },
        { text: prompt },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          scores: {
            type: Type.OBJECT,
            properties: {
              contentAccuracy: { type: Type.NUMBER },
              informationRichness: { type: Type.NUMBER },
              creativity: { type: Type.NUMBER },
              balancedParticipation: { type: Type.NUMBER },
            },
            required: ["contentAccuracy", "informationRichness", "creativity", "balancedParticipation"],
          },
          comment: { type: Type.STRING },
          transcript: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                german: { type: Type.STRING, description: "Testo originale in tedesco" },
                italian: { type: Type.STRING, description: "Traduzione in italiano" }
              },
              required: ["german", "italian"]
            }
          }
        },
        required: ["scores", "comment", "transcript"],
      },
    },
  });

  const rawJson = JSON.parse(response.text);

  const scores = rawJson.scores as Record<string, number>;
  const totalPoints = Object.values(scores).reduce((a, b) => a + b, 0);

  // Calcolo voto finale: (punti ottenuti / punti totali) * 5 + 1
  const finalGrade = (totalPoints / 20) * 5 + 1;

  return {
    studentNames: metadata.studentNames,
    region: metadata.region,
    date: new Date().toLocaleDateString('it-IT'),
    scores: rawJson.scores,
    totalPoints,
    finalGrade: parseFloat(finalGrade.toFixed(1)),
    comment: rawJson.comment,
    transcript: rawJson.transcript || []
  };
};

import React, { useState, useRef } from 'react';
import { 
  Mic, 
  Upload, 
  FileAudio, 
  CheckCircle, 
  AlertCircle, 
  Download, 
  RefreshCw,
  Info,
  GraduationCap,
  Star,
  FileText
} from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { evaluatePodcast } from './services/geminiService';
import { EvaluationResult, ProcessingStep } from './types';

const App: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [studentNames, setStudentNames] = useState('');
  const [region, setRegion] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<EvaluationResult | null>(null);
  const [steps, setSteps] = useState<ProcessingStep[]>([
    { label: 'Caricamento audio...', status: 'pending' },
    { label: 'Analisi del contenuto...', status: 'pending' },
    { label: 'Valutazione criteri...', status: 'pending' },
    { label: 'Generazione feedback e trascrizione...', status: 'pending' },
  ]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setError(null);
    }
  };

  const updateStep = (index: number, status: ProcessingStep['status']) => {
    setSteps(prev => prev.map((step, i) => i === index ? { ...step, status } : step));
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleEvaluate = async () => {
    if (!file || !studentNames || !region) {
      setError('Inserisci tutti i campi obbligatori (Nomi, Regione e File Audio).');
      return;
    }

    setLoading(true);
    setError(null);
    setResult(null);
    setSteps(prev => prev.map(s => ({ ...s, status: 'pending' })));

    try {
      updateStep(0, 'loading');
      const base64 = await fileToBase64(file);
      updateStep(0, 'completed');

      updateStep(1, 'loading');
      updateStep(2, 'loading');
      const evaluation = await evaluatePodcast(base64, file.type, {
        studentNames,
        region,
      });
      updateStep(1, 'completed');
      updateStep(2, 'completed');
      updateStep(3, 'completed');

      setResult(evaluation);
    } catch (err: any) {
      setError('Errore durante la valutazione: ' + (err.message || 'Errore sconosciuto'));
      setSteps(prev => prev.map(s => s.status === 'loading' ? { ...s, status: 'error' } : s));
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const downloadTranscript = () => {
    if (!result || !result.transcript) return;

    let content = `TRASCRIZIONE PODCAST - ${result.region}\n`;
    content += `Studenti: ${result.studentNames}\n`;
    content += `Data: ${result.date}\n`;
    content += `------------------------------------------\n\n`;

    result.transcript.forEach((line, index) => {
      content += `[DE]: ${line.german}\n`;
      content += `[IT]: ${line.italian}\n\n`;
    });

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Trascrizione_${result.region}_${result.studentNames.replace(/\s+/g, '_')}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const downloadPDF = () => {
    if (!result) return;

    try {
      const doc = new jsPDF();
      const primaryColor: [number, number, number] = [37, 99, 235]; // Blue-600

      doc.setFontSize(22);
      doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
      doc.text('Valutazione Podcast Scolastico', 14, 22);

      doc.setFontSize(11);
      doc.setTextColor(100);
      doc.text(`Progetto: Regioni d'Italia`, 14, 30);
      doc.text(`Regione: ${result.region} | Data: ${result.date}`, 14, 36);

      doc.setFontSize(16);
      doc.setTextColor(217, 119, 6); // Amber-600
      doc.setFont('helvetica', 'bold');
      doc.text(`VOTO FINALE: ${result.finalGrade.toFixed(1)}`, 140, 30);

      autoTable(doc, {
        startY: 45,
        head: [['Informazioni', 'Valore']],
        body: [
          ['Studenti', result.studentNames],
          ['Regione', result.region],
        ],
