                  </button>
                  <button
                    onClick={downloadTranscript}
                    className="sm:col-span-1 bg-indigo-600 text-white py-5 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 group"
                  >
