import React, { useState, useRef } from 'react';
import { 
  Mic, 
  Upload, 
  FileAudio, 
  CheckCircle, 
  AlertCircle, 
  Download, 
  RefreshCw,
  Info,
  GraduationCap,
  Star,
  FileText
} from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { evaluatePodcast } from './services/geminiService';
import { EvaluationResult, ProcessingStep } from './types';

const App: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [studentNames, setStudentNames] = useState('');
  const [region, setRegion] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<EvaluationResult | null>(null);
  const [steps, setSteps] = useState<ProcessingStep[]>([
    { label: 'Caricamento audio...', status: 'pending' },
    { label: 'Analisi del contenuto...', status: 'pending' },
    { label: 'Valutazione criteri...', status: 'pending' },
    { label: 'Generazione feedback e trascrizione...', status: 'pending' },
  ]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setError(null);
    }
  };

  const updateStep = (index: number, status: ProcessingStep['status']) => {
    setSteps(prev => prev.map((step, i) => i === index ? { ...step, status } : step));
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleEvaluate = async () => {
    if (!file || !studentNames || !region) {
      setError('Inserisci tutti i campi obbligatori (Nomi, Regione e File Audio).');
      return;
    }

    setLoading(true);
    setError(null);
    setResult(null);
    setSteps(prev => prev.map(s => ({ ...s, status: 'pending' })));

    try {
      updateStep(0, 'loading');
      const base64 = await fileToBase64(file);
      updateStep(0, 'completed');

      updateStep(1, 'loading');
      updateStep(2, 'loading');
      const evaluation = await evaluatePodcast(base64, file.type, {
        studentNames,
        region,
      });
      updateStep(1, 'completed');
      updateStep(2, 'completed');
      updateStep(3, 'completed');

      setResult(evaluation);
    } catch (err: any) {
      setError('Errore durante la valutazione: ' + (err.message || 'Errore sconosciuto'));
      setSteps(prev => prev.map(s => s.status === 'loading' ? { ...s, status: 'error' } : s));
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const downloadTranscript = () => {
    if (!result || !result.transcript) return;

    let content = `TRASCRIZIONE PODCAST - ${result.region}\n`;
    content += `Studenti: ${result.studentNames}\n`;
    content += `Data: ${result.date}\n`;
    content += `------------------------------------------\n\n`;

    result.transcript.forEach((line, index) => {
      content += `[DE]: ${line.german}\n`;
      content += `[IT]: ${line.italian}\n\n`;
    });

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Trascrizione_${result.region}_${result.studentNames.replace(/\s+/g, '_')}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const downloadPDF = () => {
    if (!result) return;

    try {
      const doc = new jsPDF();
      const primaryColor: [number, number, number] = [37, 99, 235]; // Blue-600

      doc.setFontSize(22);
      doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
      doc.text('Valutazione Podcast Scolastico', 14, 22);

      doc.setFontSize(11);
      doc.setTextColor(100);
      doc.text(`Progetto: Regioni d'Italia`, 14, 30);
      doc.text(`Regione: ${result.region} | Data: ${result.date}`, 14, 36);

      doc.setFontSize(16);
      doc.setTextColor(217, 119, 6); // Amber-600
      doc.setFont('helvetica', 'bold');
      doc.text(`VOTO FINALE: ${result.finalGrade.toFixed(1)}`, 140, 30);

      autoTable(doc, {
        startY: 45,
        head: [['Informazioni', 'Valore']],
        body: [
          ['Studenti', result.studentNames],
          ['Regione', result.region],
        ],
        theme: 'striped',
        headStyles: { fillColor: primaryColor },
      });

      autoTable(doc, {
        startY: (doc as any).lastAutoTable.finalY + 10,
        head: [['Kriterium', 'Descrizione', 'Punkte']],
        body: [
          ['Inhalte sind richtig', 'Correttezza contenuti', `${result.scores.contentAccuracy}/5`],
          ['Viele Informationen', 'Ricchezza informazioni', `${result.scores.informationRichness}/5`],
          ['Kreativität', 'Creatività e stile', `${result.scores.creativity}/5`],
          ['Beide sprechen mit', 'Partecipazione voci', `${result.scores.balancedParticipation}/5`],
          [{ content: 'GESAMTPUNKTZAHL (Totale Punti)', colSpan: 2, styles: { fontStyle: 'bold', fillColor: [240, 240, 240] } }, { content: `${result.totalPoints}/20`, styles: { fontStyle: 'bold', fillColor: [240, 240, 240] } }],
          [{ content: 'VOTO FINALE', colSpan: 2, styles: { fontStyle: 'bold', fillColor: [254, 243, 199] } }, { content: `${result.finalGrade.toFixed(1)}`, styles: { fontStyle: 'bold', fillColor: [254, 243, 199] } }],
        ],
        theme: 'grid',
        headStyles: { fillColor: primaryColor },
      });

      const finalY = (doc as any).lastAutoTable.finalY + 15;
      doc.setFontSize(14);
      doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
      doc.text('Feedback:', 14, finalY);

      doc.setFontSize(11);
      doc.setTextColor(40);
      doc.setFont('helvetica', 'italic');
      const splitComment = doc.splitTextToSize(result.comment, 180);
      doc.text(splitComment, 14, finalY + 8);

      doc.save(`Valutazione_${result.region}_${result.studentNames.replace(/\s+/g, '_')}.pdf`);
    } catch (e) {
      console.error("PDF generation error:", e);
      alert("Errore nella creazione del PDF.");
    }
  };

  const reset = () => {
    setFile(null);
    setResult(null);
    setError(null);
    setStudentNames('');
    setRegion('');
    setSteps(prev => prev.map(s => ({ ...s, status: 'pending' })));
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 shadow-sm">
        <div className="max-w-4xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-xl shadow-md shadow-blue-100">
              <Mic className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">Podcast Evaluator</h1>
          </div>
          <button 
            onClick={reset}
            className="text-sm font-medium text-slate-500 hover:text-blue-600 flex items-center gap-1 transition-colors px-3 py-1.5 rounded-lg hover:bg-slate-50"
          >
            <RefreshCw className="w-4 h-4" /> Reset
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-8">
        {!result ? (
          <div className="grid gap-6">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
              <div className="p-6 border-b border-slate-100 bg-slate-50/50">
                <h2 className="text-lg font-semibold text-slate-800 flex items-center gap-2">
                  <Info className="w-5 h-5 text-blue-500" /> Dettagli Valutazione
                </h2>
              </div>
              <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase">Nomi Studenti *</label>
                  <input 
                    type="text" 
                    value={studentNames}
                    onChange={(e) => setStudentNames(e.target.value)}
                    placeholder="Es: Anna e Simone"
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase">Regione *</label>
                  <input 
                    type="text" 
                    value={region}
                    onChange={(e) => setRegion(e.target.value)}
                    placeholder="Es: Sardegna"
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  />
                </div>
              </div>
            </div>

            <div 
              className={`bg-white rounded-2xl shadow-sm border-2 border-dashed transition-all p-12 flex flex-col items-center justify-center gap-4 cursor-pointer hover:border-blue-400 group ${file ? 'border-blue-400 bg-blue-50/20' : 'border-slate-200'}`}
              onClick={() => fileInputRef.current?.click()}
            >
              <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="audio/*" className="hidden" />
              <div className={`p-5 rounded-full transition-transform group-hover:scale-110 ${file ? 'bg-blue-100 text-blue-600 shadow-lg shadow-blue-50' : 'bg-slate-100 text-slate-400'}`}>
                {file ? <FileAudio className="w-12 h-12" /> : <Upload className="w-12 h-12" />}
              </div>
              <div className="text-center">
                <p className="text-lg font-semibold text-slate-800">{file ? file.name : 'Seleziona il Podcast'}</p>
                <p className="text-sm text-slate-400 mt-1 italic">Trascina qui il file audio registrato</p>
              </div>
            </div>

            {error && (
              <div className="bg-red-50 border border-red-200 rounded-xl p-4 flex items-center gap-3 text-red-700 animate-in fade-in zoom-in duration-200">
                <AlertCircle className="w-5 h-5 flex-shrink-0" />
                <p className="text-sm font-medium">{error}</p>
              </div>
            )}

            <button
              onClick={handleEvaluate}
              disabled={loading || !file || !studentNames || !region}
              className={`w-full py-5 rounded-2xl font-bold text-white shadow-xl transition-all active:scale-[0.98] ${loading || !file || !studentNames || !region ? 'bg-slate-300 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'}`}
            >
              {loading ? <RefreshCw className="w-6 h-6 animate-spin mx-auto" /> : 'Analizza Podcast'}
            </button>

            {loading && (
              <div className="bg-white rounded-2xl p-6 border border-slate-200 shadow-sm space-y-4">
                <div className="space-y-3">
                  {steps.map((step, idx) => (
                    <div key={idx} className="flex items-center gap-3">
                      {step.status === 'completed' ? <CheckCircle className="w-5 h-5 text-green-500" /> : 
                       step.status === 'loading' ? <RefreshCw className="w-5 h-5 text-blue-500 animate-spin" /> : 
                       <div className="w-5 h-5 rounded-full border-2 border-slate-200" />}
                      <span className={`text-sm ${step.status === 'loading' ? 'text-blue-600 font-medium' : 'text-slate-500'}`}>{step.label}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700">
            <div className="bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden">
              <div className="bg-gradient-to-br from-blue-600 via-blue-700 to-indigo-800 p-10 text-white relative">
                <div className="absolute top-0 right-0 p-8 opacity-10">
                   <Mic className="w-32 h-32" />
                </div>
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 relative z-10">
                  <div className="flex-1">
                    <p className="text-xs uppercase tracking-[0.2em] opacity-80 font-black">Report Podcast</p>
                    <h2 className="text-4xl font-extrabold mt-2 tracking-tight">{result.region}</h2>
                    <p className="mt-2 font-medium bg-white/10 w-fit px-3 py-1 rounded-lg backdrop-blur-sm border border-white/10">{result.studentNames}</p>
                  </div>
                  <div className="flex flex-wrap gap-4 justify-center md:justify-end">
                    <div className="bg-white/10 backdrop-blur-md text-white rounded-3xl px-6 py-4 text-center border border-white/20">
                      <p className="text-4xl font-black leading-none">{result.totalPoints}</p>
                      <p className="text-[10px] uppercase font-bold mt-2 tracking-widest opacity-70">Punti / 20</p>
                    </div>
                    <div className="bg-amber-400 text-amber-950 rounded-3xl px-8 py-6 text-center shadow-2xl border-2 border-amber-300 transform md:scale-110">
                      <div className="flex items-center justify-center gap-2 mb-1">
                        <Star className="w-4 h-4 fill-amber-950" />
                        <span className="text-[10px] uppercase font-bold tracking-widest">Voto Finale</span>
                      </div>
                      <p className="text-6xl font-black leading-none">{result.finalGrade.toFixed(1)}</p>
                    </div>
                  </div>
                </div>
              </div>

              <div className="p-10">
