                </div>

                <div className="mt-16 space-y-6">
                  <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-100 pb-2">Errori in Italiano / Contenuto</h3>
                  {result.detailedErrors.length > 0 ? (
                    <div className="grid grid-cols-1 gap-4">
                      {result.detailedErrors.map((err, idx) => (
                        <div key={idx} className="bg-white rounded-2xl border border-slate-200 p-5 flex gap-4 hover:border-red-100 transition-colors shadow-sm">
